// ─── Email helper (used by auth to create Supabase accounts) ─────────────────
function nameToEmail(name) {
  // Real email overrides for specific players
  const EMAIL_MAP = { 'Pat West': 'tourintelligence@gmail.com' };
  if (EMAIL_MAP[name]) return EMAIL_MAP[name];
  return name.toLowerCase().replace(/[^a-z0-9]/g, '.').replace(/\.+/g, '.') + '@tour-intelligence.app';
}
